const data=require('./2500000853693-4500009648245_11011_icbu.json');
const msgs=data.messages.map(m=>({
  ts: m.message.createAt,
  sender: m.message.sender.uid.startsWith('45000') ? 'CLIENT' : 'US',
  content: (m.message.content.text||{}).content || (m.message.content.custom||{}).summary || '[card]',
})).sort((a,b)=>a.ts-b.ts);
let lastSender='';
msgs.forEach(m=>{
  const prefix = m.sender !== lastSender ? '\n--- ' : '';
  const label = m.sender === 'CLIENT' ? 'CLIENT' : 'US';
  if (m.sender !== lastSender) console.log(prefix + new Date(m.ts).toISOString().slice(0,16) + ' [' + label + ']');
  console.log('  ' + (m.content||'').substring(0,150));
  lastSender=m.sender;
});
"

